      no-repeat;
  `
}

const Container = styled.div(
  ({ theme: { color, spacing, boxShadow, typography, borderRadius } }) => css`
    display: flex;
    flex-direction: column-reverse;
    padding-bottom: ${spacing.m};
    label {
      color: ${color.label};
      font-size: ${typography.fontSize.body};
